const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/user-client');
const { CustomHook } = require('magicbell-js/dist/commonjs/user-client/http/hooks/custom-hook');
const { HttpClient } = require('magicbell-js/dist/commonjs/user-client/http/client');

const runId = process.env.ZEALT_RUN_ID;
const email = process.env.MAGICBELL_EMAIL.split('@')[0];
const apiKey = process.env.MAGICBELL_API_KEY;
const secretKey = process.env.MAGICBELL_SECRET_KEY;

const payload = {
  external_id: 'user_' + runId,
  user_email: email + '+user_' + runId + '@gmail.com',
  api_key: apiKey
};

const token = jwt.sign(payload, secretKey, { algorithm: 'HS256' });
const client = new Client({ token });

class MyHook extends CustomHook {
  async beforeRequest(request, params) {
    request.headers.set('X-MAGICBELL-USER-EXTERNAL-ID', {
      key: 'X-MAGICBELL-USER-EXTERNAL-ID',
      value: 'user_' + runId
    });
    return request;
  }
}

client.notifications.client = new HttpClient(client.config, new MyHook());

client.notifications.fetchNotification('019e8b0b-d893-7f00-95af-ebda53ad6394').then(res => {
  console.log('SUCCESS:', res.data);
}).catch(err => {
  console.error('ERROR:', err);
});
